  // REMOVED: const [isFooterVisible, setIsFooterVisible] = useState(false );
  const mainContentRef = useRef<HTMLDivElement>(null);

  // ... currentProjects logic ...

  // MODIFIED useEffect for scroll
  useEffect(() => {
    const mainContentEl = mainContentRef.current;
    if (!mainContentEl) return;

    const checkHeaderVisibility = () => {
      if (!mainContentEl) return;
      setIsHeaderScrolled(mainContentEl.scrollTop > 20);
    };

    let resizeTimeout: number;
    const debouncedCheck = () => {
      clearTimeout(resizeTimeout);
      resizeTimeout = window.setTimeout(checkHeaderVisibility, 150);
    };

    const resizeObserver = new ResizeObserver(debouncedCheck);
    const elementToObserve = mainContentEl.firstElementChild || mainContentEl;
    resizeObserver.observe(elementToObserve);

    mainContentEl.addEventListener('scroll', checkHeaderVisibility, { passive: true });

    debouncedCheck();

    return () => {
      mainContentEl.removeEventListener('scroll', checkHeaderVisibility);
      resizeObserver.disconnect();
      clearTimeout(resizeTimeout);
    };
  }, [view, currentProjects]);

  // ... other useEffects and handlers ...

